import{_ as e,c as t,o,a1 as l}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"Приложение | Руководство по Clawdbot","description":"Приложение Clawdbot: полный справочник по конфигурации, протокол Gateway WebSocket API, варианты развертывания и руководство по разработке.","frontmatter":{"title":"Приложение | Руководство по Clawdbot","sidebarTitle":"Конфигурация, развертывание, разработка","subtitle":"Приложение","description":"Приложение Clawdbot: полный справочник по конфигурации, протокол Gateway WebSocket API, варианты развертывания и руководство по разработке.","tags":[],"order":340},"headers":[],"relativePath":"ru/moltbot/moltbot/appendix/index.md","filePath":"ru/moltbot/moltbot/appendix/index.md"}'),r={name:"ru/moltbot/moltbot/appendix/index.md"};function i(n,a,s,c,d,h){return o(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="приложение" tabindex="-1">Приложение <a class="header-anchor" href="#приложение" aria-label="Permalink to &quot;Приложение&quot;">​</a></h1><p>В этой главе представлены расширенная документация и ресурсы для разработки Clawdbot, включая полный справочник по конфигурации, спецификацию протокола Gateway WebSocket API, варианты развертывания и руководство по разработке.</p><div class="info custom-block"><p class="custom-block-title">Сценарии использования</p><p>Эта глава предназначена для пользователей, которым необходимо глубоко понять внутренние механизмы Clawdbot, выполнять расширенную конфигурацию, развертывание или участвовать в разработке. Если вы только начинаете использовать, рекомендуется сначала пройти главу <a href="./../../start/getting-started/">Быстрый старт</a>.</p></div><h2 id="навигация-по-подстраницам" tabindex="-1">Навигация по подстраницам <a class="header-anchor" href="#навигация-по-подстраницам" aria-label="Permalink to &quot;Навигация по подстраницам&quot;">​</a></h2><h3 id="полныи-справочник-по-конфигурации" tabindex="-1"><a href="./config-reference/">Полный справочник по конфигурации</a> <a class="header-anchor" href="#полныи-справочник-по-конфигурации" aria-label="Permalink to &quot;[Полный справочник по конфигурации](./config-reference/)&quot;">​</a></h3><p><strong>Подробный справочник по конфигурации</strong> — охватывает все параметры конфигурации, значения по умолчанию и примеры. Найдите полную документацию по модулям Gateway, Agent, каналов, инструментов и других.</p><h3 id="протокол-gateway-websocket-api" tabindex="-1"><a href="./api-protocol/">Протокол Gateway WebSocket API</a> <a class="header-anchor" href="#протокол-gateway-websocket-api" aria-label="Permalink to &quot;[Протокол Gateway WebSocket API](./api-protocol/)&quot;">​</a></h3><p><strong>Документация по спецификации протокола</strong> — полная спецификация протокола Gateway WebSocket, включая определения конечных точек, форматы сообщений, методы аутентификации и механизмы подписки на события. Подходит для разработчиков, которым необходимо создавать собственные клиенты или интегрировать Gateway.</p><h3 id="варианты-развертывания" tabindex="-1"><a href="./deployment/">Варианты развертывания</a> <a class="header-anchor" href="#варианты-развертывания" aria-label="Permalink to &quot;[Варианты развертывания](./deployment/)&quot;">​</a></h3><p><strong>Руководство по способам развертывания</strong> — способы развертывания на различных платформах: локальная установка, Docker, VPS, Fly.io, Nix и другие. Узнайте, как запускать Clawdbot в различных средах.</p><h3 id="руководство-по-разработке" tabindex="-1"><a href="./development/">Руководство по разработке</a> <a class="header-anchor" href="#руководство-по-разработке" aria-label="Permalink to &quot;[Руководство по разработке](./development/)&quot;">​</a></h3><p><strong>Документация для разработчиков</strong> — сборка из исходного кода, разработка плагинов, тестирование и процесс внесения вклада. Узнайте, как участвовать в разработке проекта Clawdbot или писать собственные плагины.</p><h2 id="рекомендации-по-пути-обучения" tabindex="-1">Рекомендации по пути обучения <a class="header-anchor" href="#рекомендации-по-пути-обучения" aria-label="Permalink to &quot;Рекомендации по пути обучения&quot;">​</a></h2><p>В зависимости от ваших потребностей выберите подходящий путь обучения:</p><h3 id="инженеры-по-конфигурации-и-эксплуатации" tabindex="-1">Инженеры по конфигурации и эксплуатации <a class="header-anchor" href="#инженеры-по-конфигурации-и-эксплуатации" aria-label="Permalink to &quot;Инженеры по конфигурации и эксплуатации&quot;">​</a></h3><ol><li>Сначала прочитайте <a href="./config-reference/">Полный справочник по конфигурации</a> — узнайте все настраиваемые параметры</li><li>Ознакомьтесь с <a href="./deployment/">Вариантами развертывания</a> — выберите подходящую схему развертывания</li><li>При необходимости обратитесь к документации Gateway WebSocket API для интеграции</li></ol><h3 id="разработчики-приложении" tabindex="-1">Разработчики приложений <a class="header-anchor" href="#разработчики-приложении" aria-label="Permalink to &quot;Разработчики приложений&quot;">​</a></h3><ol><li>Прочитайте <a href="./api-protocol/">Протокол Gateway WebSocket API</a> — поймите механизм протокола</li><li>Ознакомьтесь с <a href="./config-reference/">Полным справочником по конфигурации</a> — узнайте, как настраивать связанные функции</li><li>Обращайтесь к примерам протокола для создания клиентов</li></ol><h3 id="разработчики-плагинов-функции" tabindex="-1">Разработчики плагинов/функций <a class="header-anchor" href="#разработчики-плагинов-функции" aria-label="Permalink to &quot;Разработчики плагинов/функций&quot;">​</a></h3><ol><li>Прочитайте <a href="./development/">Руководство по разработке</a> — узнайте среду разработки и процесс сборки</li><li>Углубитесь в <a href="./api-protocol/">Протокол Gateway WebSocket API</a> — поймите архитектуру Gateway</li><li>Обратитесь к <a href="./config-reference/">Полному справочнику по конфигурации</a> — узнайте систему конфигурации</li></ol><h2 id="предварительные-требования" tabindex="-1">Предварительные требования <a class="header-anchor" href="#предварительные-требования" aria-label="Permalink to &quot;Предварительные требования&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Предварительные знания</p><p>Перед углублением в эту главу рекомендуется завершить следующее:</p><ul><li>✅ Завершили <a href="./../../start/getting-started/">Быстрый старт</a></li><li>✅ Настроили как минимум один канал (например, <a href="./../../platforms/whatsapp/">WhatsApp</a> или <a href="./../../platforms/telegram/">Telegram</a>)</li><li>✅ Поняли базовую конфигурацию моделей ИИ (см. <a href="./../../advanced/models-auth/">Модели ИИ и аутентификация</a>)</li><li>✅ Имеете базовое понимание JSON-конфигурационных файлов и TypeScript</li></ul></div><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения обучения в этой главе вы можете:</p><ul><li><strong>Выполнить расширенную конфигурацию</strong> — обратитесь к <a href="./config-reference/">Полному справочнику по конфигурации</a> для настройки вашего Clawdbot</li><li><strong>Развернуть в производственной среде</strong> — следуйте <a href="./deployment/">Вариантам развертывания</a> для выбора подходящей схемы развертывания</li><li><strong>Разработать собственные функции</strong> — обратитесь к <a href="./development/">Руководству по разработке</a> для написания плагинов или внесения вклада в код</li><li><strong>Углубиться в другие функции</strong> — изучите главу <a href="./../../advanced/">Расширенные функции</a> о системах управления сессиями, инструментов и других</li></ul><div class="tip custom-block"><p class="custom-block-title">Поиск помощи</p><p>Если вы столкнулись с проблемами при использовании, обратитесь к <a href="./../../faq/troubleshooting/">Устранению неполадок</a> для получения решений распространенных проблем.</p></div>',26)])])}const f=e(r,[["render",i]]);export{b as __pageData,f as default};
